UPDATE stage_prompts SET config = '{"stage": 5, "laneTitle": "Final Movie", "note": "Kept per-scene, as confirmed \u2014 each scene generates its own clip independently; stitching all scene clips into one finished commercial happens externally, outside this tool. The source doc describes a single whole-project ''Final Production Render'' assembling every approved stage at once \u2014 adapted below to per-scene scope: ''this scene''s Blueprint/Character/Prop/Background Sheets + Music Brief'' instead of the whole project''s. Cross-scene concerns (adding new scenes, transitions between scenes) trimmed out since they don''t apply to a single clip.", "assemblyOrder": ["masterSheetPrompt", "yourDescription", "universalStyle"], "universalStyle": {"key": "production_bible_universal", "label": "Universal Production Bible Style", "text": "Maintain one consistent visual identity.\n\n\u2022 Apple keynote presentation quality\n\u2022 Cannes Lions commercial quality\n\u2022 Netflix production consistency\n\u2022 Weta Workshop attention to detail\n\nThe final video must feel like it was directed by an award-winning commercial director and produced by a premium production house."}, "items": {"movie": {"label": "Final Movie Clip", "note": "content.geminiInstruction removed \u2014 animation direction is now a plain designer-set field, no Gemini drafting. Transition/B-roll moved here from Stage 4 \u2014 they''re video-editing concepts (how this clip cuts into the next one, what supplementary footage to cut in) that a still keyframe image can''t represent, so they belong to the actual clip, not the Scene Blueprint.", "content": {"fieldsSchema": [{"key": "direction", "label": "Animation direction", "type": "textarea", "presets": ["Slow push-in on the subject, hold at the end.", "Static shot with a gentle handheld sway.", "Pan left to right, following the product into frame.", "Slow pull back to reveal the full scene.", "Quick zoom in for emphasis, then hold steady."]}, {"key": "duration", "label": "Duration (sec)", "type": "pill", "options": ["4", "6", "8", "10", "15", "30"]}, {"key": "broll", "label": "B-roll", "type": "pill", "options": ["None", "Product Macro Shot", "Product Spin", "Slow-Motion Detail", "Texture Close-up", "Lifestyle Cutaway"], "optionHelp": {"None": "What: no supplementary footage. When to use: the main shot alone tells the story. Example: a simple testimonial clip, no product insert needed.", "Product Macro Shot": "What: an extreme close-up insert of the product. When to use: to highlight fine detail like label or texture. Example: a close-up of a jar''s lid twisting open.", "Product Spin": "What: a rotating, 360\u00b0-style shot of the product. When to use: to show its full form and branding. Example: a bottle slowly rotating to reveal its label.", "Slow-Motion Detail": "What: a slowed-down insert emphasizing a small action. When to use: for a satisfying, premium-feel moment. Example: cream dripping slowly off a spoon.", "Texture Close-up": "What: a tight shot on surface texture. When to use: to emphasize quality or ingredients. Example: a close-up on the weave of a fabric.", "Lifestyle Cutaway": "What: a brief shot of the product in real use. When to use: to show it fitting into daily life. Example: someone casually sipping the drink at their desk."}}, {"key": "transition", "label": "Transition", "type": "pill", "options": ["Hard Cut", "Whip Pan", "Match Cut", "Fade", "Zoom Transition"], "optionHelp": {"Hard Cut": "What: an instant cut with no effect. When to use: the default choice for most edits, keeps pacing snappy. Example: cutting straight from the product shot to the customer''s reaction.", "Whip Pan": "What: a fast, blurred camera swipe between shots. When to use: for energetic, fast-paced transitions. Example: whipping from the kitchen to the dining table.", "Match Cut": "What: a cut where the next shot''s composition or action matches the previous one. When to use: for a smooth, clever visual continuity. Example: a jar lid closing cuts to a door closing in the next scene.", "Fade": "What: the shot gradually fades to/from black or the next shot. When to use: for a soft, emotional, or scene-ending transition. Example: fading out after the final call-to-action line.", "Zoom Transition": "What: a quick zoom into or out of frame to transition. When to use: for punchy, modern social-style edits. Example: zooming into the logo before cutting to the next scene."}}]}, "outputInstructions": [{"key": "master_final_production_render_prompt", "label": "Master Final Production Render Prompt (per scene)", "default": true, "text": "Create this scene''s final commercial-quality clip exactly from its approved Scene Blueprint.\n\nOBJECTIVE\n\nExecute this scene''s approved Scene Blueprint without inventing new story elements.\nMaintain complete continuity with the Character Sheets, Prop Sheets, Background Sheet, and Music Brief referenced for this scene.\n\nFOLLOW EXACTLY\n\n\u2022 This scene''s Blueprint\n\u2022 The Character Sheets featured in this scene\n\u2022 The Prop Sheets featured in this scene\n\u2022 This scene''s Background Sheet\n\u2022 The Music Brief\n\nCONTINUITY\n\n\u2022 Character identity\n\u2022 Hair & wardrobe\n\u2022 Props\n\u2022 Backgrounds\n\u2022 Time of day\n\u2022 Weather\n\u2022 Lighting\n\u2022 Camera direction\n\u2022 Screen direction\n\u2022 Dialogue timing\n\u2022 Emotion progression\n\u2022 Branding\n\nCINEMATOGRAPHY\n\n\u2022 Hollywood commercial quality\n\u2022 Premium advertising cinematography\n\u2022 Natural human motion\n\u2022 Realistic facial animation\n\u2022 Accurate lip sync (if dialogue exists)\n\u2022 Correct eye-line\n\u2022 Natural hand interactions\n\u2022 Realistic physics\n\u2022 Smooth camera movement\n\u2022 Consistent color grading\n\u2022 Feature-film lighting\n\u2022 Premium depth of field\n\nEDITING\n\n\u2022 Respect the planned shot duration\n\u2022 Honor the specified transition into/out of this clip\n\u2022 Include the specified B-roll insert, if any\n\u2022 Preserve pacing\n\u2022 Match music cues\n\u2022 Match sound effects\n\u2022 Broadcast-ready finish\n\nDO NOT\n\n\u2022 Change story\n\u2022 Add characters\n\u2022 Change wardrobe\n\u2022 Change props\n\u2022 Redesign locations\n\u2022 Change branding\n\nDIMENSIONS\n\nRender at the highest resolution Flow supports (minimum 1080p), in the aspect ratio matching the target platform \u2014 vertical 9:16 for Reels/Shorts/TikTok, 16:9 for YouTube/landscape.\n\nOUTPUT\n\nGenerate ONE polished, commercial-quality video clip for this scene, faithful to its approved Scene Blueprint and the Production Bible."}]}, "final_video": {"label": "Final Video", "note": "One per project, auto-created when Stage 4 locks (alongside the per-scene Movie pairing), never manually deletable. Upload-only \u2014 designer stitches every scene''s approved clip together externally and uploads the one finished result here. This is the only thing the customer''s public download for Stage 5 actually serves (see pay.ts) \u2014 the per-scene clips stay a production/designer artifact, not something the customer needs to see."}}}' WHERE stage = 5;
